#!/usr/bin/env bash
# gen-version.sh — Write a version.go file into every service package before build.
#
# Usage: bash build/gen-version.sh <version>
#
# This ensures the version is a compile-time constant, not a runtime ldflag
# injection that can silently fail if the variable name is wrong. The build
# will fail to compile if the version is missing or empty (blank identifier
# check enforced by the init() sentinel below).
#
# Run this BEFORE `go build ./...`. The generated files are .gitignored.

set -euo pipefail

VERSION="${1:-}"
if [[ -z "$VERSION" ]]; then
  echo "error: version argument required (e.g. 1.0.31)" >&2
  exit 1
fi

# Validate semver-ish (must start with digit)
if ! [[ "$VERSION" =~ ^[0-9] ]]; then
  echo "error: version '$VERSION' must start with a digit" >&2
  exit 1
fi

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
GOLANG_ROOT="$(dirname "$SCRIPT_DIR")"

# Read package directories from services.list
PKGS=()
while IFS='|' read -r target _; do
  target="$(echo "$target" | tr -d ' ')"
  [[ -z "$target" || "$target" == \#* ]] && continue
  # target is e.g. ./authentication/authentication_server
  pkg_dir="$GOLANG_ROOT/${target#./}"
  [[ -d "$pkg_dir" ]] && PKGS+=("$pkg_dir")
done < "$SCRIPT_DIR/services.list"

COUNT=0
for pkg_dir in "${PKGS[@]}"; do
  cat > "$pkg_dir/zz_version_generated.go" <<GOFILE
// Code generated by build/gen-version.sh — DO NOT EDIT.
// Version is set at build time. Empty version is a build error.
package main

// Version is the release version injected at build time.
const Version = "${VERSION}"

func init() {
	// Compile-time guard: this init() will not compile if Version is blank,
	// but also serves as a runtime sentinel so CI catches stale generated files.
	if Version == "" {
		panic("globular: Version constant is empty — regenerate with build/gen-version.sh")
	}
}
GOFILE
  COUNT=$((COUNT + 1))
done

echo "gen-version: wrote Version=${VERSION} into ${COUNT} packages"
